}

export interface ImportResult {
  nodesInserted: number;
  nodesUpdated: number;
  edgesInserted: number;
  edgesSkipped: number;
}

export class Database {
  private db: sqlite3.Database;
  private run: (sql: string, params?: unknown[]) => Promise<sqlite3.RunResult>;
  private get: (sql: string, params?: unknown[]) => Promise<unknown>;
  private all: (sql: string, params?: unknown[]) => Promise<unknown[]>;

  constructor(dbPath: string) {
    this.db = new sqlite3.Database(dbPath);
    this.run = promisify(this.db.run.bind(this.db));
    this.get = promisify(this.db.get.bind(this.db));
    this.all = promisify(this.db.all.bind(this.db));
  }

  async initialize(): Promise<void> {
    await this.run(`
      CREATE TABLE IF NOT EXISTS nodes (
        id TEXT PRIMARY KEY,
        type TEXT NOT NULL,
        name TEXT NOT NULL,
        signature TEXT,
        doc TEXT,
        file TEXT,
        line INTEGER,
        column INTEGER,
        language TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `);

    await this.run(`
      CREATE TABLE IF NOT EXISTS edges (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        source_id TEXT NOT NULL,
        target_id TEXT NOT NULL,
        type TEXT NOT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(source_id, target_id, type),
        FOREIGN KEY (source_id) REFERENCES nodes(id) ON DELETE CASCADE,
        FOREIGN KEY (target_id) REFERENCES nodes(id) ON DELETE CASCADE
      )
    `);

    await this.run(`
      CREATE INDEX IF NOT EXISTS idx_nodes_type ON nodes(type)
    `);

    await this.run(`
      CREATE INDEX IF NOT EXISTS idx_nodes_name ON nodes(name)
    `);

    await this.run(`
      CREATE INDEX IF NOT EXISTS idx_edges_source ON edges(source_id)
    `);

    await this.run(`
      CREATE INDEX IF NOT EXISTS idx_edges_target ON edges(target_id)
    `);
  }

  async beginTransaction(): Promise<void> {
    await this.run('BEGIN TRANSACTION');
  }

  async commit(): Promise<void> {
    await this.run('COMMIT');
  }

  async rollback(): Promise<void> {
    await this.run('ROLLBACK');
  }

  async insertNode(node: Node): Promise<'inserted' | 'updated'> {
    const existing = await this.get(
      'SELECT id FROM nodes WHERE id = ?',
      [node.id]
    ) as { id: string } | undefined;

    if (existing) {
      await this.run(
        `UPDATE nodes SET
          type = ?, name = ?, signature = ?, doc = ?,
          file = ?, line = ?, column = ?, language = ?,
          updated_at = CURRENT_TIMESTAMP
        WHERE id = ?`,
        [
          node.type, node.name, node.signature, node.doc,
          node.file, node.line, node.column, node.language,
          node.id
        ]
      );
      return 'updated';
    }

    await this.run(
      `INSERT INTO nodes (id, type, name, signature, doc, file, line, column, language)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        node.id, node.type, node.name, node.signature, node.doc,
        node.file, node.line, node.column, node.language
      ]
    );
    return 'inserted';
  }

  async insertNodesBatch(nodes: Node[]): Promise<{ inserted: number; updated: number }> {
    const stmt = this.db.prepare(
      `INSERT INTO nodes (id, type, name, signature, doc, file, line, column, language)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
       ON CONFLICT(id) DO UPDATE SET
         type = excluded.type,
         name = excluded.name,
         signature = excluded.signature,
         doc = excluded.doc,
         file = excluded.file,
         line = excluded.line,
         column = excluded.column,
         language = excluded.language,
         updated_at = CURRENT_TIMESTAMP`
    );

    const runAsync = promisify(stmt.run.bind(stmt));
    let inserted = 0;
    let updated = 0;

    for (const node of nodes) {
      const existing = await this.get(
        'SELECT id FROM nodes WHERE id = ?',
        [node.id]
      ) as { id: string } | undefined;

      await runAsync([
        node.id, node.type, node.name, node.signature, node.doc,
        node.file, node.line, node.column, node.language
      ]);

      if (existing) {
        updated++;
      } else {
        inserted++;
      }
    }

    stmt.finalize();
    return { inserted, updated };
  }

  async insertEdge(edge: Edge): Promise<boolean> {
    try {
      await this.run(
        `INSERT INTO edges (source_id, target_id, type)
         VALUES (?, ?, ?)
         ON CONFLICT(source_id, target_id, type) DO NOTHING`,
        [edge.sourceId, edge.targetId, edge.type]
      );
      return true;
    } catch {
      return false;
    }
  }

  async insertEdgesBatch(edges: Edge[]): Promise<{ inserted: number; skipped: number }> {
    const stmt = this.db.prepare(
      `INSERT INTO edges (source_id, target_id, type)
       VALUES (?, ?, ?)
       ON CONFLICT(source_id, target_id, type) DO NOTHING`
    );

    const runAsync = promisify(stmt.run.bind(stmt));
    let inserted = 0;
    let skipped = 0;

    for (const edge of edges) {
      const result = await runAsync([edge.sourceId, edge.targetId, edge.type]) as { changes: number };
      if (result.changes > 0) {
        inserted++;
      } else {
        skipped++;
      }
    }

    stmt.finalize();
    return { inserted, skipped };
  }

  async nodeExists(id: string): Promise<boolean> {
    const result = await this.get(
      'SELECT 1 FROM nodes WHERE id = ?',
      [id]
    ) as { 1: number } | undefined;
    return result !== undefined;
  }

  async getNode(id: string): Promise<Node | undefined> {
    return await this.get(
      'SELECT * FROM nodes WHERE id = ?',
      [id]
    ) as Node | undefined;
  }

