export interface SCIPSymbol {
  symbol: string;
  name: string;
  kind: string;
  signature?: string;
  documentation?: string[];
  location?: {
    path: string;
    range: {
      start: { line: number; character: number };
      end: { line: number; character: number };
    };
  };
}

export interface SCIPEdge {
  source: string;
  target: string;
  type: string;
}

export interface SCIPIndex {
  metadata: {
    version: string;
    language: string;
    projectRoot: string;
  };
  symbols: SCIPSymbol[];
  edges: SCIPEdge[];
}

export interface ImportOptions {
  batchSize?: number;
  onProgress?: (processed: number, total: number) => void;
}

export class SCIPIndexImporter {
  private db: Database;

  constructor(db: Database) {
    this.db = db;
  }

  async importIndex(index: SCIPIndex, options: ImportOptions = {}): Promise<ImportResult> {
    const { batchSize = 1000, onProgress } = options;
    const result: ImportResult = {
      nodesInserted: 0,
      nodesUpdated: 0,
      edgesInserted: 0,
      edgesSkipped: 0,
    };

    await this.db.beginTransaction();

    try {
      const nodes = this.convertSymbolsToNodes(index.symbols, index.metadata.language);
      const totalItems = nodes.length + index.edges.length;
      let processed = 0;

      for (let i = 0; i < nodes.length; i += batchSize) {
        const batch = nodes.slice(i, i + batchSize);
        const batchResult = await this.db.insertNodesBatch(batch);

        result.nodesInserted += batchResult.inserted;
        result.nodesUpdated += batchResult.updated;

        processed += batch.length;
        onProgress?.(processed, totalItems);
      }

      const edges = this.convertEdges(index.edges);

      for (let i = 0; i < edges.length; i += batchSize) {
        const batch = edges.slice(i, i + batchSize);
        const batchResult = await this.db.insertEdgesBatch(batch);

        result.edgesInserted += batchResult.inserted;
        result.edgesSkipped += batchResult.skipped;

        processed += batch.length;
        onProgress?.(processed, totalItems);
      }

      await this.db.commit();
      return result;
    } catch (error) {
      await this.db.rollback();
      throw error;
    }
  }

  async importIncremental(
    index: SCIPIndex,
    options: ImportOptions = {}
  ): Promise<ImportResult> {
    const existingSymbols = await this.getExistingSymbolIds();
    const newSymbols = index.symbols.filter(s => !existingSymbols.has(s.symbol));
    const updatedSymbols = index.symbols.filter(s => existingSymbols.has(s.symbol));

    const newIndex: SCIPIndex = {
      ...index,
      symbols: [...newSymbols, ...updatedSymbols],
    };

    return this.importIndex(newIndex, options);
  }

  private convertSymbolsToNodes(symbols: SCIPSymbol[], language: string): Node[] {
    return symbols.map(symbol => ({
      id: symbol.symbol,
      type: this.mapSymbolKind(symbol.kind),
      name: symbol.name,
      signature: symbol.signature,
      doc: symbol.documentation?.join('\n'),
      file: symbol.location?.path,
      line: symbol.location?.range?.start?.line,
      column: symbol.location?.range?.start?.character,
      language,
    }));
  }

  private convertEdges(edges: SCIPEdge[]): Edge[] {
    return edges.map(edge => ({
      sourceId: edge.source,
      targetId: edge.target,
      type: edge.type,
    }));
  }

  private async getExistingSymbolIds(): Promise<Set<string>> {
    const db = this.db as unknown as {
      all: (sql: string) => Promise<Array<{ id: string }>>;
    };
    const rows = await db.all('SELECT id FROM nodes');
    return new Set(rows.map(r => r.id));
  }

  private mapSymbolKind(kind: string): string {
    const kindMap: Record<string, string> = {
      'namespace': 'namespace',
      'package': 'package',
      'class': 'class',
      'method': 'method',
      'property': 'property',
      'field': 'field',
      'constructor': 'constructor',
      'enum': 'enum',
      'interface': 'interface',
      'function': 'function',
      'variable': 'variable',
      'constant': 'constant',
      'string': 'string',
      'number': 'number',
      'boolean': 'boolean',
      'array': 'array',
    };

    return kindMap[kind.toLowerCase()] || 'unknown';
  }
}

export async function importSCIPIndex(
  dbPath: string,
  index: SCIPIndex,
  options?: ImportOptions
): Promise<ImportResult> {
  const db = new Database(dbPath);

  try {
    await db.initialize();
    const importer = new SCIPIndexImporter(db);
    return await importer.importIndex(index, options);
  } finally {
    await db.close();
  }
}

export async function importSCIPIndexIncremental(
  dbPath: string,
  index: SCIPIndex,
  options?: ImportOptions
): Promise<ImportResult> {
  const db = new Database(dbPath);

  try {
    await db.initialize();
    const importer = new SCIPIndexImporter(db);
    return await importer.importIncremental(index, options);
  } finally {
    await db.close();
  }
}
